async function fetchJson<T>(url: string): Promise<T> {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`${url} failed with ${response.status}`);
  }
  return (await response.json()) as T;
}

export function fetchCoreRuntime(baseUrl = ""): Promise<CoreRuntime> {
  return fetchJson<CoreRuntime>(`${baseUrl}/runtime`);
}

export function fetchCoreContract(baseUrl = ""): Promise<CoreContract> {
  return fetchJson<CoreContract>(`${baseUrl}/contract`);
}

